  1	import * as React from 'react';
  2	import { Button, Tabs, Tab, ButtonVariant } from '@patternfly/react-core';
  3	import { MatchBuilder } from './MatchBuilder';
  4	import { Matches } from './Matches';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { WorkloadOverview } from '../../../types/ServiceInfo';
  7	import { TrafficShifting, WorkloadWeight } from '../TrafficShifting';
  8	import { FaultInjection, FaultInjectionRoute } from '../FaultInjection';
  9	import { PFColors } from '../../Pf/PfColors';
 10	import { RequestTimeouts, TimeoutRetryRoute } from '../RequestTimeouts';
 11	import { t } from 'utils/I18nUtils';
 12	
 13	type Props = {
 14	  // MatchBuilder props
 15	  category: string;
 16	  operator: string;
 17	  headerName: string;
 18	  matchValue: string;
 19	  isValid: boolean;
 20	  onSelectCategory: (category: string) => void;
 21	  onHeaderNameChange: (headerName: string) => void;
 22	  onSelectOperator: (operator: string) => void;
 23	  onMatchValueChange: (matchValue: string) => void;
 24	  onAddMatch: () => void;
 25	
 26	  // Matches props
 27	  matches: string[];
 28	  onRemoveMatch: (match: string) => void;
 29	
 30	  workloads: WorkloadOverview[];
 31	  weights: WorkloadWeight[];
 32	  onSelectWeights: (valid: boolean, workloads: WorkloadWeight[]) => void;
 33	
 34	  faultInjectionRoute: FaultInjectionRoute;
 35	  onSelectFaultInjection: (valid: boolean, faultInjectionRoute: FaultInjectionRoute) => void;
 36	
 37	  timeoutRetryRoute: TimeoutRetryRoute;
 38	  onSelectTimeoutRetry: (valid: boolean, timeoutRetryRoute: TimeoutRetryRoute) => void;
 39	
 40	  // RuleBuilder
 41	  validationMsg: string;
 42	  onAddRule: () => void;
 43	};
 44	
 45	type State = {
 46	  isWorkloadSelector: boolean;
 47	  ruleTabKey: number;
 48	};
 49	
 50	const addRuleStyle = kialiStyle({
 51	  width: '100%',
 52	  textAlign: 'right'
 53	});
 54	
 55	const validationStyle = kialiStyle({
 56	  marginRight: 20,
 57	  color: PFColors.Red100,
 58	  display: 'inline'
 59	});
 60	
 61	export class RuleBuilder extends React.Component<Props, State> {
 62	  constructor(props) {
 63	    super(props);
 64	    this.state = {
 65	      isWorkloadSelector: false,
 66	      ruleTabKey: 0
 67	    };
 68	  }
 69	
 70	  onWorkloadsToggle = () => {
 71	    this.setState({
 72	      isWorkloadSelector: !this.state.isWorkloadSelector
 73	    });
 74	  };
 75	
 76	  ruleHandleTabClick = (_event, tabIndex) => {
 77	    this.setState({
 78	      ruleTabKey: tabIndex
 79	    });
 80	  };
 81	
 82	  render() {
 83	    return (
 84	      <>
 85	        <Tabs isFilled={true} activeKey={this.state.ruleTabKey} onSelect={this.ruleHandleTabClick}>
 86	          <Tab eventKey={0} title={t('Request Matching')} data-test={'Request Matching'}>
 87	            <div style={{ marginTop: '20px' }}>
 88	              <MatchBuilder {...this.props} />
 89	              <Matches {...this.props} />
 90	            </div>
 91	          </Tab>
 92	          <Tab eventKey={1} title={t('Route To')} data-test={'Route To'}>
 93	            <div
 94	              style={{
 95	                marginBottom: '10px'
 96	              }}
 97	            >
 98	              <TrafficShifting
 99	                showValid={false}
100	                workloads={this.props.workloads}
101	                initWeights={this.props.weights}
102	                showMirror={true}
103	                onChange={this.props.onSelectWeights}
104	              />
105	            </div>
106	          </Tab>
107	          <Tab eventKey={2} title={t('Fault Injection')} data-test={'Fault Injection'}>
108	            <div style={{ marginTop: '10px' }}>
109	              <FaultInjection
110	                initFaultInjectionRoute={this.props.faultInjectionRoute}
111	                onChange={this.props.onSelectFaultInjection}
112	              />
113	            </div>
114	          </Tab>
115	          <Tab eventKey={3} title={t('Request Timeouts')} data-test={'Request Timeouts'}>
116	            <div style={{ marginTop: '10px' }}>
117	              <RequestTimeouts
118	                initTimeoutRetry={this.props.timeoutRetryRoute}
119	                onChange={this.props.onSelectTimeoutRetry}
120	              />
121	            </div>
122	          </Tab>
123	        </Tabs>
124	        <div className={addRuleStyle}>
125	          <span>
126	            {this.props.validationMsg.length > 0 && <div className={validationStyle}>{this.props.validationMsg}</div>}
127	            <Button
128	              variant={ButtonVariant.secondary}
129	              isDisabled={!this.props.isValid}
130	              onClick={this.props.onAddRule}
131	              data-test="add-route"
132	            >
133	              {t('Add Route Rule')}
134	            </Button>
135	          </span>
136	        </div>
137	      </>
138	    );
139	  }
140	}

